import{_ as e,c as l,ag as r,o as i}from"./chunks/framework.mHuDn-wg.js";const m=JSON.parse('{"title":"图像分析","description":"","frontmatter":{},"headers":[],"relativePath":"计算机/软件使用/图像处理.md","filePath":"计算机/软件使用/图像处理.md","lastUpdated":null}'),t={name:"计算机/软件使用/图像处理.md"};function o(n,a,h,s,d,u){return i(),l("div",null,a[0]||(a[0]=[r('<h1 id="图像分析" tabindex="-1">图像分析 <a class="header-anchor" href="#图像分析" aria-label="Permalink to &quot;图像分析&quot;">​</a></h1><h2 id="imagej" tabindex="-1">ImageJ <a class="header-anchor" href="#imagej" aria-label="Permalink to &quot;ImageJ&quot;">​</a></h2><ul><li>简介：用于科学图像处理的可编写脚本的 Java 应用程序.\\</li><li>主要功能是计算面积和像素值，测量距离和角度，创建密度直方图以及线剖面图。还提供其他标准图像处理功能，例如对比度处理、锐化、平滑、边缘检测和中值滤波等。</li><li>#开源 #免费 #跨平台 #java</li><li>官网：<a href="https://imagej.net/" target="_blank" rel="noreferrer">ImageJ Wiki</a></li><li>文档: <a href="https://imagej.net/ij/docs/index.html" target="_blank" rel="noreferrer">Documentation</a></li><li>Github：<a href="https://github.com/imagej" target="_blank" rel="noreferrer">ImageJ · GitHub</a></li><li>教程：<a href="https://imagej.net/learn/" target="_blank" rel="noreferrer">Introduction (imagej.net)</a></li><li>安装: 官网下载安装即可</li></ul><h3 id="基于imaej的软件" tabindex="-1">基于imaej的软件 <a class="header-anchor" href="#基于imaej的软件" aria-label="Permalink to &quot;基于imaej的软件&quot;">​</a></h3><ul><li>Fiji(fiji is just ImageJ) 是 ImageJ 的一个发行版，预装了很多生物医学分析常用插件.</li><li>ImageJ2是ImageJ的升级版，包括一些原始 ImageJ 中没有的附加功能</li></ul><h3 id="应用" tabindex="-1">应用 <a class="header-anchor" href="#应用" aria-label="Permalink to &quot;应用&quot;">​</a></h3><p>测量物体尺寸</p><ul><li>打开图像文件</li><li>设置比例: Analyze -&gt; Set Scale</li><li>测量长度: 选择直线, 在图中手动拖选要测量的长度, 按ctrl+M会出现测量窗口, 重复直到需要测量的物体全部选完.</li><li>导出测量数据: 在测量窗口中按ctrl+S保存为csv文件</li><li>在 Analyze -&gt; Set Measurements 中可以选择需要输出的数据</li></ul><p>添加标尺</p><ul><li>Analyze -&gt; Tools -&gt; Scale Bar</li></ul><h2 id="nano-measurer" tabindex="-1">Nano Measurer <a class="header-anchor" href="#nano-measurer" aria-label="Permalink to &quot;Nano Measurer&quot;">​</a></h2><ul><li>一款用于分析扫描电子显微镜（SEM）和透射电子显微镜（TEM）图像的简单易用的长度统计分析软件.</li><li>可以分析与尺寸有关的任何图片，比如求晶面间距, 纳米线纳米颗粒的长度、直径、和孔径等尺寸统计分析.</li><li>采用VisualBasic6.0程序开发，具有占用内存小，操作简单，数据可以导入origin作图.</li><li><strong>不支持tif格式</strong></li><li>#windows #免费</li><li><a href="https://zhuanlan.zhihu.com/p/58241959" target="_blank" rel="noreferrer">尺寸统计软件Nano measurer详细使用教程（附下载链接） - 知乎</a></li></ul><h2 id="image-pro-plus" tabindex="-1">Image-Pro Plus <a class="header-anchor" href="#image-pro-plus" aria-label="Permalink to &quot;Image-Pro Plus&quot;">​</a></h2><ul><li>一款用于科学图像处理和分析的软件</li><li>应用: 合成荧光图片、免疫组化图片光密度测量、凝胶电泳图片的测量、凝胶电泳图片的测量、荧光强度测量、测量鼠脑切片的梗塞面积测量心肌纤维截面积、找两张图片的差异之处、测量划痕实验的细胞间距、测量网状的细胞壁等等.</li><li>#商业软件</li><li><a href="https://zhuanlan.zhihu.com/p/662886076" target="_blank" rel="noreferrer">图像分析软件介绍，Image J、Fiji、Image pro plus - 知乎</a></li><li><a href="https://zhuanlan.zhihu.com/p/72836778" target="_blank" rel="noreferrer">顶级图像处理软件 | Image-Pro Plus 6.0 - 知乎</a></li></ul><h2 id="nanoscope-analysis" tabindex="-1">Nanoscope Analysis <a class="header-anchor" href="#nanoscope-analysis" aria-label="Permalink to &quot;Nanoscope Analysis&quot;">​</a></h2><ul><li>简介：Bruker的AFM离线数据分析软件</li><li><a href="https://confluence.cornell.edu/display/CNF/AFM+NanoScope+Analysis" target="_blank" rel="noreferrer">AFM NanoScope Analysis - Cornell NanoScale Science and Technology Facility - Dashboard</a></li><li><a href="https://www.shiyanjia.com/knowledge/articleinfo-1008.html?from=0" target="_blank" rel="noreferrer">AFM 离线软件NanoScope Analysis使用教程-科学指南针</a></li></ul><h1 id="图像处理" tabindex="-1">图像处理 <a class="header-anchor" href="#图像处理" aria-label="Permalink to &quot;图像处理&quot;">​</a></h1><h2 id="inpaint" tabindex="-1">Inpaint <a class="header-anchor" href="#inpaint" aria-label="Permalink to &quot;Inpaint&quot;">​</a></h2><ul><li>简介：轻量图片去水印软件</li><li>#windows #mac #免费 #webserve</li><li>官网：<a href="https://theinpaint.com/" target="_blank" rel="noreferrer">Remove Unwanted Objects &amp; Fix Imperfections with Inpaint Online! (theinpaint.com)</a></li></ul><h2 id="photoshop" tabindex="-1">Photoshop <a class="header-anchor" href="#photoshop" aria-label="Permalink to &quot;Photoshop&quot;">​</a></h2><ul><li>#商业软件</li></ul><h2 id="gimp" tabindex="-1">GIMP <a class="header-anchor" href="#gimp" aria-label="Permalink to &quot;GIMP&quot;">​</a></h2><ul><li>GNU Image Manipulation Program（GNU图像处理程序）, 是Peter Mattis和Spencer Kimhall开发的免费照片和图像处理和创作工具, 类似Photoshop</li><li>#开源 #免费 #跨平台</li><li>官网: <a href="https://www.gimp.org/downloads/" target="_blank" rel="noreferrer">GIMP - Downloads</a></li><li><a href="https://zhuanlan.zhihu.com/p/566842377" target="_blank" rel="noreferrer">免费开源的图像处理软件GIMP下载安装（Windows) - 知乎</a></li></ul><h1 id="图像绘制" tabindex="-1">图像绘制 <a class="header-anchor" href="#图像绘制" aria-label="Permalink to &quot;图像绘制&quot;">​</a></h1><h2 id="powerpoint" tabindex="-1">powerpoint <a class="header-anchor" href="#powerpoint" aria-label="Permalink to &quot;powerpoint&quot;">​</a></h2><h2 id="autocad" tabindex="-1">AutoCAD <a class="header-anchor" href="#autocad" aria-label="Permalink to &quot;AutoCAD&quot;">​</a></h2><h2 id="illustrator" tabindex="-1">Illustrator <a class="header-anchor" href="#illustrator" aria-label="Permalink to &quot;Illustrator&quot;">​</a></h2><h2 id="三维和模型图" tabindex="-1">三维和模型图 <a class="header-anchor" href="#三维和模型图" aria-label="Permalink to &quot;三维和模型图&quot;">​</a></h2><h3 id="_3ds-max" tabindex="-1">3ds Max <a class="header-anchor" href="#_3ds-max" aria-label="Permalink to &quot;3ds Max&quot;">​</a></h3><h3 id="solidworks" tabindex="-1">SolidWorks <a class="header-anchor" href="#solidworks" aria-label="Permalink to &quot;SolidWorks&quot;">​</a></h3><h3 id="c4d" tabindex="-1">C4D <a class="header-anchor" href="#c4d" aria-label="Permalink to &quot;C4D&quot;">​</a></h3><h3 id="blender" tabindex="-1">Blender <a class="header-anchor" href="#blender" aria-label="Permalink to &quot;Blender&quot;">​</a></h3><ul><li>Blender是一款免费且开源的三维计算机图形软件</li><li>#开源 #免费 #跨平台</li><li><a href="https://www.blendercn.org/downloadme" target="_blank" rel="noreferrer">Blender下载和汉化 – Blender中国社区</a></li></ul>',33)]))}const p=e(t,[["render",o]]);export{m as __pageData,p as default};
